{
  "title": "`INNER JOIN` का उपयोग",
  "group": "SQL जॉइन्स",
  "options": [
    {
      "text": "दोनों टेबल्स से अनमैच्ड पंक्तियाँ लौटाता है",
      "hint": "यह OUTER JOIN का काम है।"
    },
    {
      "text": "दोनों टेबल्स की सभी पंक्तियाँ लौटाता है, अनमैच्ड पंक्तियों के लिए NULL के साथ",
      "hint": "यह FULL OUTER JOIN का काम है।"
    },
    {
      "text": "उन पंक्तियों को लौटाता है जो दोनों टेबल्स में जॉइन कंडीशन को संतुष्ट करती हैं",
      "hint": "बिल्कुल सही! केवल मिलान वाली पंक्तियाँ ही रिटर्न होती हैं।"
    },
    {
      "text": "राइट टेबल से अनमैच्ड पंक्तियाँ लौटाता है",
      "hint": "यह RIGHT JOIN का काम है।"
    }
  ],
  "questionProse": [
    "SQL में `INNER JOIN` क्या करता है?"
  ],
  "explanationProse": [
    "`INNER JOIN` केवल वही पंक्तियाँ रिटर्न करता है जहाँ जॉइन कंडीशन दोनों टेबल्स में मेल खाती है। जो पंक्तियाँ मेल नहीं खातीं, वे रिजल्ट सेट से बाहर रहती हैं। सीधे शब्दों में: केवल कॉमन डेटा ही मिलेगा।"
  ]
}
